'use client';

/**
 * ContractInteraction — ABI-based contract function call UI.
 *
 * Renders read (view/pure) and write (nonpayable/payable) function cards
 * parsed from a deployed contract's ABI. Read calls use a viem publicClient
 * (no wallet required); write calls use wagmi's useWriteContract (wallet required).
 *
 * Observability:
 * - Every call result (success or error) fires the onCallResult callback,
 *   which should feed into TransactionConsole via useTransactionLog.addEntry.
 * - Errors include the full revert reason / wagmi error message.
 * - Parse failures for ABI are caught defensively and logged to console.error.
 */

import { useState, useMemo, useCallback } from 'react';
import { createPublicClient, http } from 'viem';
import { useWriteContract, useAccount } from 'wagmi';
import {
  parseAbiFunctions,
  solidityTypeToInputType,
  parseInputValue,
  formatOutputValue,
  type AbiFunction,
} from '@/lib/abi-utils';
import { monadTestnet } from '@/lib/wagmi-config';
import type { TransactionLogEntry } from '@/hooks/useTransactionLog';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface ContractInteractionProps {
  abi: unknown[];
  contractAddress: string;
  onCallResult: (entry: Omit<TransactionLogEntry, 'id' | 'timestamp'>) => void;
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

export function ContractInteraction({
  abi,
  contractAddress,
  onCallResult,
}: ContractInteractionProps) {
  // Memoize the public client for read calls
  const publicClient = useMemo(
    () =>
      createPublicClient({
        chain: monadTestnet,
        transport: http(),
      }),
    [],
  );

  // Parse ABI defensively
  const { readFunctions, writeFunctions } = useMemo(() => {
    try {
      return parseAbiFunctions(abi);
    } catch (err) {
      console.error('[ContractInteraction] Failed to parse ABI:', err);
      return { readFunctions: [] as AbiFunction[], writeFunctions: [] as AbiFunction[] };
    }
  }, [abi]);

  const isEmpty = readFunctions.length === 0 && writeFunctions.length === 0;

  return (
    <div className="space-y-3">
      <h3 className="text-sm font-semibold text-cyan-400 uppercase tracking-wider">
        Contract Interaction
      </h3>

      {isEmpty ? (
        <p className="text-sm text-gray-500 italic">No callable functions</p>
      ) : (
        <>
          {/* Read functions */}
          {readFunctions.length > 0 && (
            <div className="space-y-2">
              <p className="text-xs font-medium text-gray-400">Read Functions</p>
              {readFunctions.map((fn) => (
                <ReadFunctionCard
                  key={fn.name}
                  fn={fn}
                  abi={abi}
                  contractAddress={contractAddress}
                  publicClient={publicClient}
                  onCallResult={onCallResult}
                />
              ))}
            </div>
          )}

          {/* Write functions */}
          {writeFunctions.length > 0 && (
            <div className="space-y-2">
              <p className="text-xs font-medium text-gray-400">Write Functions</p>
              {writeFunctions.map((fn) => (
                <WriteFunctionCard
                  key={fn.name}
                  fn={fn}
                  abi={abi}
                  contractAddress={contractAddress}
                  onCallResult={onCallResult}
                />
              ))}
            </div>
          )}
        </>
      )}
    </div>
  );
}

// ---------------------------------------------------------------------------
// ReadFunctionCard
// ---------------------------------------------------------------------------

interface ReadCardProps {
  fn: AbiFunction;
  abi: unknown[];
  contractAddress: string;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  publicClient: any;
  onCallResult: ContractInteractionProps['onCallResult'];
}

function ReadFunctionCard({
  fn,
  abi,
  contractAddress,
  publicClient,
  onCallResult,
}: ReadCardProps) {
  const [inputs, setInputs] = useState<Record<string, string>>({});
  const [result, setResult] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const handleInputChange = useCallback(
    (paramName: string, value: string) => {
      setInputs((prev) => ({ ...prev, [paramName]: value }));
    },
    [],
  );

  const handleCall = useCallback(async () => {
    setLoading(true);
    setError(null);
    setResult(null);

    try {
      const args = fn.inputs.map((p) =>
        parseInputValue(inputs[p.name] ?? '', p.type),
      );

      const data = await publicClient.readContract({
        address: contractAddress as `0x${string}`,
        abi,
        functionName: fn.name,
        args: args.length > 0 ? args : undefined,
      });

      const formatted = formatOutputValue(data);
      setResult(formatted);

      onCallResult({
        type: 'call',
        status: 'success',
        message: `${fn.name}() → ${formatted}`,
        details: { contractName: fn.name },
      });
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : String(err);
      setError(msg);

      onCallResult({
        type: 'call',
        status: 'error',
        message: `${fn.name}() failed: ${msg}`,
        details: { errors: [msg] },
      });
    } finally {
      setLoading(false);
    }
  }, [fn, inputs, abi, contractAddress, publicClient, onCallResult]);

  return (
    <div className="rounded-lg border border-gray-700 bg-gray-800 p-3 space-y-2">
      <p className="text-sm font-mono text-cyan-300">{fn.name}()</p>

      {fn.inputs.map((param) => (
        <FunctionInput
          key={param.name || param.type}
          param={param}
          value={inputs[param.name] ?? ''}
          onChange={(v) => handleInputChange(param.name, v)}
        />
      ))}

      <button
        onClick={handleCall}
        disabled={loading}
        className="w-full px-3 py-1.5 rounded-md bg-cyan-700 hover:bg-cyan-600 text-white text-xs font-medium transition-colors disabled:opacity-50 flex items-center justify-center gap-2"
      >
        {loading && <Spinner />}
        Call
      </button>

      {result !== null && (
        <div className="p-2 rounded bg-gray-900 border border-emerald-800 text-xs text-emerald-300 font-mono break-all">
          ↳ {result}
        </div>
      )}

      {error && (
        <div className="p-2 rounded bg-gray-900 border border-red-800 text-xs text-red-300 break-all">
          ✗ {error}
        </div>
      )}
    </div>
  );
}

// ---------------------------------------------------------------------------
// WriteFunctionCard
// ---------------------------------------------------------------------------

interface WriteCardProps {
  fn: AbiFunction;
  abi: unknown[];
  contractAddress: string;
  onCallResult: ContractInteractionProps['onCallResult'];
}

function WriteFunctionCard({
  fn,
  abi,
  contractAddress,
  onCallResult,
}: WriteCardProps) {
  const { isConnected } = useAccount();
  const { writeContract, isPending } = useWriteContract();

  const [inputs, setInputs] = useState<Record<string, string>>({});
  const [msgValue, setMsgValue] = useState('');
  const [result, setResult] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleInputChange = useCallback(
    (paramName: string, value: string) => {
      setInputs((prev) => ({ ...prev, [paramName]: value }));
    },
    [],
  );

  const handleSend = useCallback(() => {
    setError(null);
    setResult(null);

    const args = fn.inputs.map((p) =>
      parseInputValue(inputs[p.name] ?? '', p.type),
    );

    // Build params
    const params: Record<string, unknown> = {
      address: contractAddress as `0x${string}`,
      abi,
      functionName: fn.name,
      args: args.length > 0 ? args : undefined,
    };

    // payable: send MON value
    if (fn.payable && msgValue.trim()) {
      try {
        // Convert MON (ether) to wei: 1 MON = 1e18 wei
        const wei = BigInt(
          Math.floor(parseFloat(msgValue) * 1e18),
        );
        params.value = wei;
      } catch {
        // ignore parse errors, send without value
      }
    }

    writeContract(
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      params as any,
      {
        onSuccess(hash) {
          setResult(`Tx: ${hash}`);
          onCallResult({
            type: 'call',
            status: 'success',
            message: `${fn.name}() → tx ${hash}`,
            details: { txHash: hash },
          });
        },
        onError(err) {
          const msg = err.message || String(err);
          setError(msg);
          onCallResult({
            type: 'call',
            status: 'error',
            message: `${fn.name}() failed: ${msg}`,
            details: { errors: [msg] },
          });
        },
      },
    );
  }, [fn, inputs, msgValue, abi, contractAddress, writeContract, onCallResult]);

  if (!isConnected) {
    return (
      <div className="rounded-lg border border-gray-700 bg-gray-800 p-3 space-y-2">
        <p className="text-sm font-mono text-amber-300">{fn.name}()</p>
        <p className="text-xs text-gray-500 italic">
          Connect wallet to call write functions
        </p>
      </div>
    );
  }

  return (
    <div className="rounded-lg border border-gray-700 bg-gray-800 p-3 space-y-2">
      <p className="text-sm font-mono text-amber-300">{fn.name}()</p>

      {fn.inputs.map((param) => (
        <FunctionInput
          key={param.name || param.type}
          param={param}
          value={inputs[param.name] ?? ''}
          onChange={(v) => handleInputChange(param.name, v)}
        />
      ))}

      {/* Payable value field */}
      {fn.payable && (
        <div className="flex items-center gap-2">
          <label className="text-xs text-gray-400 shrink-0">Value (MON)</label>
          <input
            type="text"
            value={msgValue}
            onChange={(e) => setMsgValue(e.target.value)}
            placeholder="0.0"
            className="flex-1 px-2 py-1 rounded bg-gray-900 border border-gray-600 text-xs text-gray-200 focus:border-amber-500 focus:outline-none"
          />
        </div>
      )}

      <button
        onClick={handleSend}
        disabled={isPending}
        className="w-full px-3 py-1.5 rounded-md bg-amber-700 hover:bg-amber-600 text-white text-xs font-medium transition-colors disabled:opacity-50 flex items-center justify-center gap-2"
      >
        {isPending && <Spinner />}
        Send
      </button>

      {result !== null && (
        <div className="p-2 rounded bg-gray-900 border border-emerald-800 text-xs text-emerald-300 font-mono break-all">
          ↳ {result}
        </div>
      )}

      {error && (
        <div className="p-2 rounded bg-gray-900 border border-red-800 text-xs text-red-300 break-all">
          ✗ {error}
        </div>
      )}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Shared sub-components
// ---------------------------------------------------------------------------

function FunctionInput({
  param,
  value,
  onChange,
}: {
  param: { name: string; type: string };
  value: string;
  onChange: (v: string) => void;
}) {
  const inputType = solidityTypeToInputType(param.type);

  if (inputType === 'checkbox') {
    return (
      <label className="flex items-center gap-2 text-xs text-gray-300">
        <input
          type="checkbox"
          checked={value === 'true'}
          onChange={(e) => onChange(e.target.checked ? 'true' : 'false')}
          className="rounded border-gray-600 bg-gray-900 text-cyan-500 focus:ring-cyan-600"
        />
        {param.name || param.type}{' '}
        <span className="text-gray-500">({param.type})</span>
      </label>
    );
  }

  return (
    <div className="flex items-center gap-2">
      <label className="text-xs text-gray-400 shrink-0 min-w-[60px]">
        {param.name || param.type}{' '}
        <span className="text-gray-600">({param.type})</span>
      </label>
      <input
        type="text"
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={param.type}
        className="flex-1 px-2 py-1 rounded bg-gray-900 border border-gray-600 text-xs text-gray-200 placeholder-gray-600 focus:border-cyan-500 focus:outline-none"
      />
    </div>
  );
}

function Spinner() {
  return (
    <svg
      className="animate-spin h-3 w-3 text-current"
      fill="none"
      viewBox="0 0 24 24"
    >
      <circle
        className="opacity-25"
        cx="12"
        cy="12"
        r="10"
        stroke="currentColor"
        strokeWidth="4"
      />
      <path
        className="opacity-75"
        fill="currentColor"
        d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"
      />
    </svg>
  );
}

