"use client";

import { useState, useEffect, useCallback } from "react";
import AIDiffViewer from "@/components/ide/AIDiffViewer";
import { VibeStatus } from "../components/VibeStatus";
import {
  getContractSource,
  deployContract,
  compileContract,
  analyzeError,
  getVibeScore,
  getDeployStatus,
} from "@/lib/api-client";
import type { CompileResult, VibeScoreResult } from "@/lib/api-client";
import { VibeScoreDashboard } from "@/components/ide/VibeScoreDashboard";
import { ContractInteraction } from "@/components/ide/ContractInteraction";
import { parseSolcErrors } from "@/lib/solc-error-parser";
import { useAuth } from "@/lib/auth-context";
import { useTransactionLog } from "@/hooks/useTransactionLog";
import { WalletConnectModal } from "@/components/WalletConnectModal";
import { IDELayout } from "@/components/ide/IDELayout";
import { EditorPanel } from "@/components/ide/EditorPanel";
import { SidebarPanel } from "@/components/ide/SidebarPanel";
import { ConsolePanel } from "@/components/ide/ConsolePanel";
import { TransactionConsole } from "@/components/ide/TransactionConsole";
import MonacoEditor from "@/components/ide/MonacoEditor";

const CONTRACT_OPTIONS = [
  { value: "FailingContract", label: "FailingContract", desc: "배포 에러 테스트" },
  { value: "FixedContract", label: "FixedContract", desc: "수정된 버전" },
  { value: "PectraTest", label: "PectraTest", desc: "Pectra 옵코드 테스트" },
  { value: "ParallelConflict", label: "ParallelConflict", desc: "병렬 실행 테스트" },
] as const;

export default function VibeLoomPage() {
  const { isAuthenticated, user, login, logout } = useAuth();

  const [contractType, setContractType] = useState("FailingContract");
  const [contractSource, setContractSource] = useState<string>("");

  const loadContractSource = useCallback((type: string) => {
    getContractSource(type)
      .then((data) => {
        setContractSource(data.source ?? "");
      })
      .catch(() => setContractSource(""));
  }, []);

  useEffect(() => {
    loadContractSource(contractType);
  }, [contractType, loadContractSource]);

  const [isDeploying, setIsDeploying] = useState(false);
  const [deployResult, setDeployResult] = useState<{ address?: string; success?: boolean } | null>(null);
  const [error, setError] = useState("");
  const [isAiFixing, setIsAiFixing] = useState(false);
  const [errorDiff, setErrorDiff] = useState<{
    original: string;
    fixed: string;
    summary: string;
  } | null>(null);

  const [vibeScore, setVibeScore] = useState<VibeScoreResult | null>(null);
  const [isVibeScoreLoading, setIsVibeScoreLoading] = useState(false);
  const [showWalletModal, setShowWalletModal] = useState(false);
  const [editorInstance, setEditorInstance] = useState<any>(null);
  const [monacoInstance, setMonacoInstance] = useState<any>(null);
  const [isCompiling, setIsCompiling] = useState(false);
  const [compileResult, setCompileResult] = useState<CompileResult | null>(null);

  const { entries, addEntry, clearLog } = useTransactionLog();

  const handleEditorReady = useCallback((editor: any, monaco: any) => {
    setEditorInstance(editor);
    setMonacoInstance(monaco);
  }, []);

  const handleEditorChange = useCallback((value: string) => {
    setContractSource(value);
  }, []);

  // Clear Monaco markers when contract source changes
  useEffect(() => {
    if (editorInstance && monacoInstance) {
      monacoInstance.editor.setModelMarkers(editorInstance.getModel(), "solc", []);
    }
  }, [contractSource, editorInstance, monacoInstance]);

  const handleCompile = async () => {
    if (!contractSource.trim()) return;
    setIsCompiling(true);
    // Clear previous markers
    if (editorInstance && monacoInstance) {
      monacoInstance.editor.setModelMarkers(editorInstance.getModel(), "solc", []);
    }
    addEntry({ type: "compile", status: "pending", message: "Compiling..." });
    try {
      const result = await compileContract(contractSource);
      setCompileResult(result);
      addEntry({
        type: "compile",
        status: "success",
        message: `Compiled: ${result.contractName || "Contract"}`,
        details: { contractName: result.contractName, abi: result.abi },
      });
    } catch (err) {
      const msg = (err as Error).message || "Compilation failed";
      // Parse for inline markers
      const markers = parseSolcErrors(msg);
      if (editorInstance && monacoInstance) {
        monacoInstance.editor.setModelMarkers(editorInstance.getModel(), "solc", markers);
      }
      addEntry({
        type: "compile",
        status: "error",
        message: msg,
        details: { errors: [msg] },
      });
    } finally {
      setIsCompiling(false);
    }
  };

  const handleDeploy = async () => {
    if (!contractSource.trim()) {
      setError("배포할 컨트랙트 소스가 없습니다.");
      return;
    }

    // Gate: check paymaster status before deploying (if authenticated)
    if (isAuthenticated) {
      try {
        const status = await getDeployStatus();
        if (!status.canUseRelay) {
          setShowWalletModal(true);
          return;
        }
      } catch {
        // If status check fails, proceed with server deploy attempt
      }
    }

    setIsDeploying(true);
    setError("");
    setDeployResult(null);
    setErrorDiff(null);
    addEntry({ type: "deploy", status: "pending", message: "Deploying..." });

    try {
      const data = await deployContract(contractSource);
      setDeployResult({ address: data.address, success: true });
      addEntry({
        type: "deploy",
        status: "success",
        message: "Deployed",
        details: { address: data.address, txHash: data.txHash },
      });
    } catch (err: unknown) {
      const errObj = err as { message?: string };
      const errMsg = errObj?.message || "배포 중 오류가 발생했습니다.";
      setError(errMsg);
      addEntry({ type: "deploy", status: "error", message: errMsg });
      setIsAiFixing(true);
      try {
        const result = await analyzeError(err, contractSource);
        if (result.analysis) {
          setErrorDiff({
            original: contractSource,
            fixed: result.analysis.fixedCode,
            summary: result.analysis.explanation,
          });
        }
      } catch {
        // 무시
      } finally {
        setIsAiFixing(false);
      }
    } finally {
      setIsDeploying(false);
    }
  };

  const handleApplyFix = (fixedCode: string) => {
    setContractSource(fixedCode);
  };

  const handleAnalyzeVibeScore = () => {
    if (!contractSource.trim()) return;
    setIsVibeScoreLoading(true);
    setVibeScore(null);
    getVibeScore(contractSource)
      .then((data) => {
        setVibeScore(data);
      })
      .catch(() => setVibeScore(null))
      .finally(() => setIsVibeScoreLoading(false));
  };

  const handleWalletDeploySuccess = (address: string, _txHash: string) => {
    setShowWalletModal(false);
    setDeployResult({ address, success: true });
    setError("");
    setErrorDiff(null);
  };

  /* ── Toolbar for EditorPanel ─────────────────────────────────── */
  const editorToolbar = (
