"use client";

import { useState, useEffect } from "react";

const MOBILE_BREAKPOINT = "(max-width: 767px)";

/**
 * SSR-safe viewport detection hook.
 * Returns `true` when the viewport is narrower than 768px (mobile).
 * Defaults to `false` during SSR to avoid hydration mismatch.
 */
export function useIsMobile(): boolean {
  const [isMobile, setIsMobile] = useState(false);

  useEffect(() => {
    const mql = window.matchMedia(MOBILE_BREAKPOINT);
    // Sync initial client-side value
    setIsMobile(mql.matches);

    const handler = (e: MediaQueryListEvent) => {
      setIsMobile(e.matches);
    };

    mql.addEventListener("change", handler);
    return () => mql.removeEventListener("change", handler);
  }, []);

  return isMobile;
}

export default useIsMobile;

"use client";

interface VibeScoreDashboardProps {
  score: number;
  suggestions?: string[];
  conflicts?: number;
  reExecutions?: number;
  gasEfficiency?: number;
  engineBased?: boolean;
  loading?: boolean;
}

/**
 * VibeScoreDashboard — rich Vibe-Score visualization.
 *
 * Three sections:
 * 1. Circular SVG gauge with color-coded score
 * 2. Stats grid: conflicts · re-executions · gas efficiency
 * 3. Suggestion cards with amber accent
 *
 * Observability: Pure presentational — no side effects.
 * Inspect via React DevTools props.
 */
export function VibeScoreDashboard({
  score,
  suggestions = [],
  conflicts,
  reExecutions,
  gasEfficiency,
  engineBased = false,
  loading = false,
}: VibeScoreDashboardProps) {
  // ── Color logic (reused from VibeScoreGauge) ──────────────────────────
  const scoreColor =
    score >= 80
      ? "text-emerald-400"
      : score >= 60
        ? "text-amber-400"
        : "text-red-400";

  const strokeColor =
    score >= 80
      ? "#34d399" // emerald-400
      : score >= 60
        ? "#fbbf24" // amber-400
        : "#f87171"; // red-400

  const scoreLabel =
    score >= 80
      ? "Monad 병렬 실행에 적합"
      : score >= 60
        ? "일부 최적화 권장"
        : "성능 저하 위험 요소 존재";

  // SVG circle math — 120×120 viewBox, r=52
  const radius = 52;
  const circumference = 2 * Math.PI * radius;
  const dashOffset = circumference - (score / 100) * circumference;

  // ── Loading skeleton ──────────────────────────────────────────────────
  if (loading) {
    return (
      <div className="bg-gray-800 rounded-xl border border-gray-700 p-4 space-y-4">
        <h3 className="text-gray-400 text-sm font-semibold">Vibe Score</h3>

        {/* Pulsing circle */}
        <div className="flex justify-center">
          <div className="w-28 h-28 rounded-full bg-gray-700 animate-pulse" />
        </div>

        {/* Stat box skeletons */}
        <div className="grid grid-cols-3 gap-2">
          {[0, 1, 2].map((i) => (
            <div
              key={i}
              className="bg-gray-900 rounded-lg p-3 space-y-2 animate-pulse"
            >
              <div className="h-4 w-8 bg-gray-700 rounded" />
              <div className="h-3 w-14 bg-gray-700 rounded" />
            </div>
          ))}
        </div>

        {/* Card placeholders */}
        <div className="space-y-2">
          {[0, 1].map((i) => (
            <div
              key={i}
              className="h-10 bg-gray-900 rounded-lg animate-pulse"
            />
          ))}
        </div>

        <p className="text-gray-500 text-sm text-center">분석 중...</p>
      </div>
    );
  }

  // ── Rendered dashboard ────────────────────────────────────────────────
  return (
    <div className="bg-gray-800 rounded-xl border border-gray-700 p-4 space-y-4">
      {/* Header with optional engine badge */}
      <div className="flex items-center gap-2">
        <h3 className="text-gray-400 text-sm font-semibold">Vibe Score</h3>
        {engineBased && (
          <span className="text-[10px] font-medium px-1.5 py-0.5 rounded bg-purple-900/60 text-purple-300 border border-purple-700/50">
            Engine-Based
          </span>
        )}
      </div>

      {/* Section 1: Circular gauge */}
      <div className="flex flex-col items-center gap-1">
        <svg
          width="120"
          height="120"
          viewBox="0 0 120 120"
          className="transform -rotate-90"
          aria-label={`Vibe score ${score}`}
        >
          {/* Background ring */}
          <circle
            cx="60"
            cy="60"
            r={radius}
            fill="none"
            stroke="#374151"
            strokeWidth="8"
          />
          {/* Score ring */}
          <circle
            cx="60"
            cy="60"
            r={radius}
            fill="none"
            stroke={strokeColor}
            strokeWidth="8"
            strokeLinecap="round"
            strokeDasharray={circumference}
            strokeDashoffset={dashOffset}
            className="transition-all duration-700 ease-out"
          />
        </svg>
        {/* Centered score — overlaid on SVG via negative margin */}
        <div className={`-mt-[84px] mb-[36px] text-center ${scoreColor}`}>
          <span className="text-3xl font-black">{score}</span>
        </div>
        <p className="text-gray-500 text-xs text-center">{scoreLabel}</p>
      </div>

      {/* Section 2: Stats grid */}
      <div className="grid grid-cols-3 gap-2">
        {/* Conflicts */}
        <div className="bg-gray-900 rounded-lg p-3 text-center">
          <p className="text-lg font-bold text-gray-100">
            {conflicts !== undefined ? conflicts : "—"}
          </p>
          <p className="text-[11px] text-gray-500 mt-0.5">
            💥 Conflicts
          </p>
        </div>

        {/* Re-Executions */}
        <div className="bg-gray-900 rounded-lg p-3 text-center">
          <p className="text-lg font-bold text-gray-100">
            {reExecutions !== undefined ? reExecutions : "—"}
          </p>
          <p className="text-[11px] text-gray-500 mt-0.5">
            🔄 Re-Executions
          </p>
        </div>

        {/* Gas Efficiency */}
        <div className="bg-gray-900 rounded-lg p-3 text-center">
          <p className="text-lg font-bold text-gray-100">
            {gasEfficiency !== undefined ? `${gasEfficiency}%` : "—"}
          </p>
          <p className="text-[11px] text-gray-500 mt-0.5">
            ⛽ Gas Efficiency
          </p>
        </div>
      </div>

      {/* Section 3: Suggestion cards */}
      {suggestions.length > 0 && (
        <div className="space-y-2 pt-2 border-t border-gray-700">
          <p className="text-gray-400 text-xs font-semibold">개선 제안</p>
          {suggestions.map((suggestion, idx) => (
            <div
              key={idx}
              className="flex gap-2 bg-gray-900 rounded-lg p-2.5 border-l-2 border-amber-500"
            >
              <span className="text-amber-400 text-sm flex-shrink-0">
                💡 {idx + 1}.
              </span>
              <p className="text-sm text-gray-300 line-clamp-2">
                {suggestion}
              </p>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import {
  Controller,
  Get,
  Post,
  Body,
  UseGuards,
  Req,
  Logger,
} from '@nestjs/common';
import { JwtAuthGuard } from '../auth/jwt-auth.guard';
import { PaymasterService } from './paymaster.service';
import { RelaySignedDto } from './dto/relay-signed.dto';
import { DeployStatusDto } from './dto/deploy-status.dto';

@Controller('paymaster')
export class PaymasterController {
  private readonly logger = new Logger(PaymasterController.name);

  constructor(private readonly paymasterService: PaymasterService) {}

  /**
   * GET /api/paymaster/status
   * Returns the current deploy count status for the authenticated user.
   */
  @Get('status')
  @UseGuards(JwtAuthGuard)
  async getStatus(@Req() req: any): Promise<DeployStatusDto> {
    const userId = req.user.id;
    this.logger.log(`Deploy status requested by user ${userId}`);
    return this.paymasterService.getDeployStatus(userId);
  }

  /**
   * POST /api/paymaster/relay-signed
   * Broadcasts a pre-signed transaction to the Monad testnet.
   * Requires JWT authentication.
   */
  @Post('relay-signed')
  @UseGuards(JwtAuthGuard)
  async relaySigned(
    @Req() req: any,
    @Body() dto: RelaySignedDto,
  ): Promise<{ txHash: string }> {
    const userId = req.user.id;
    this.logger.log(`Relay-signed request from user ${userId}`);
    return this.paymasterService.broadcastSignedTransaction(
      dto.signedTransaction,
    );
  }
}

