function formatTimestamp(iso: string): string {
  try {
    const d = new Date(iso);
    return d.toLocaleTimeString("en-US", {
      hour12: false,
      hour: "2-digit",
      minute: "2-digit",
      second: "2-digit",
    });
  } catch {
    return iso;
  }
}

export function TransactionConsole({ entries }: TransactionConsoleProps) {
  if (entries.length === 0) {
    return (
      <div className="flex h-full items-center justify-center text-sm text-gray-500">
        No transactions yet
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-1.5 p-1.5">
      {entries.map((entry, index) => {
        const config = statusConfig[entry.status];
        const badgeColor = typeBadgeColors[entry.type];
        const isEven = index % 2 === 0;

        return (
          <div
            key={entry.id}
            className={`rounded-md border ${config.borderColor} ${config.bgColor} px-2.5 py-1.5 shadow-sm shadow-black/10 panel-transition ${isEven ? "opacity-100" : "opacity-90"}`}
          >
            <div className="flex items-center gap-2 text-xs">
              <span className="text-gray-500 font-mono tabular-nums">
                {formatTimestamp(entry.timestamp)}
              </span>
              <span
                className={`rounded px-1.5 py-0.5 text-[10px] font-semibold uppercase ${badgeColor}`}
              >
                {entry.type}
              </span>
              <span className={config.textColor}>{config.icon}</span>
              <span className="text-gray-300 truncate">{entry.message}</span>
            </div>

            {entry.details && (
              <details className="mt-1">
                <summary className="cursor-pointer text-[10px] text-gray-500 hover:text-gray-400 transition-colors duration-150">
                  Details
                </summary>
                <pre className="mt-1 overflow-x-auto rounded bg-gray-950/80 p-1.5 font-mono text-[10px] text-gray-400">
                  {JSON.stringify(entry.details, null, 2)}
                </pre>
              </details>
            )}
          </div>
        );
      })}
    </div>
  );
}

export default TransactionConsole;

