'use client';

/**
 * AIDiffViewerInner — Monaco DiffEditor for AI fix suggestions.
 *
 * This file is never imported directly — it's lazy-loaded via
 * `next/dynamic` in `AIDiffViewer.tsx` with `ssr: false`, which
 * ensures Monaco's `window`/`document` dependencies don't break
 * server-side rendering.
 */

import { DiffEditor } from '@monaco-editor/react';

export interface AIDiffViewerProps {
  /** Original (before-fix) source code */
  original: string;
  /** Modified (after-fix) source code */
  modified: string;
  /** Optional summary/explanation banner */
  summary?: string;
  /** Called when the user clicks "Apply Fix" — receives the modified code */
  onApplyFix?: (fixedCode: string) => void;
}

export function AIDiffViewerInner({
  original,
  modified,
  summary,
  onApplyFix,
}: AIDiffViewerProps) {
  const hasFix = original !== modified;

  return (
    <div className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden">
      {summary && (
        <div className="px-4 py-2 bg-amber-900/30 border-b border-gray-700 text-amber-200 text-sm">
          {summary}
        </div>
      )}

      <DiffEditor
        height="300px"
        language="sol"
        theme="vs-dark"
        original={original}
        modified={modified}
        options={{
          readOnly: true,
          renderSideBySide: true,
          minimap: { enabled: false },
          scrollBeyondLastLine: false,
        }}
        loading={
          <div className="flex items-center justify-center h-[300px] text-gray-500">
            Loading diff...
          </div>
        }
      />

      {hasFix && onApplyFix && (
        <div className="px-4 py-3 bg-gray-900/50 border-t border-gray-700">
          <button
            type="button"
            onClick={() => onApplyFix(modified)}
            className="px-4 py-2 bg-emerald-600 hover:bg-emerald-500 text-white font-semibold rounded-lg transition-colors"
          >
            Apply Fix
          </button>
        </div>
      )}
    </div>
  );
}

